import React, { useState } from 'react';

function ProjectsPage({ data }) {
  if (!data || data.length === 0) return null;

  const visibleProjects = data;

  return (
    <section id="projects-page" className="bg-white py-8 md:py-12">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-10 md:mb-12">
          <p className="text-xs uppercase tracking-[0.35em] text-orange-500 font-semibold mb-3">
            Work
          </p>
          <h1 className="text-4xl md:text-6xl font-black text-gray-900 mb-3">
            Selected Projects
          </h1>
          <p className="text-sm md:text-base text-gray-600 max-w-2xl">
            A visual collection of brand identity and web design work inspired by editorial portfolio layouts.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-8">
          {visibleProjects.map((project, index) => (
            <div
              key={project.id}
              className="group relative rounded-[24px] overflow-hidden bg-black min-h-[360px] md:min-h-[480px] shadow-sm"
            >
              <img
                src={project.image}
                alt={project.title}
                className="absolute inset-0 w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
              />

              <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-black/5" />

              <div className="absolute top-4 md:top-5 right-4 md:right-5 flex gap-2 z-10">
                <span className="px-3 py-1.5 rounded-full bg-white/25 backdrop-blur-sm text-white text-xs font-semibold">
                  {project.year}
                </span>
                <span className="px-3 py-1.5 rounded-full bg-white/25 backdrop-blur-sm text-white text-xs font-semibold">
                  {project.company.split(',')[0]}
                </span>
              </div>

              <div className="absolute inset-x-0 bottom-0 p-5 md:p-6 text-white z-10">
                <div className="flex items-end justify-between gap-4">
                  <div>
                    <h3 className="text-2xl md:text-3xl font-black leading-tight mb-2">
                      {project.title}
                    </h3>
                    <p className="text-sm md:text-base text-white/85 max-w-md leading-relaxed">
                      {project.description}
                    </p>

                    {project.tags && project.tags.length > 0 && (
                      <div className="flex flex-wrap gap-2 mt-4">
                        {project.tags.slice(0, 2).map((tag) => (
                          <span key={tag} className="px-3 py-1 rounded-full bg-white/15 backdrop-blur-sm text-xs font-medium text-white/90 border border-white/15">
                            {tag}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>

                  <a
                    href={project.link}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="w-12 h-12 rounded-full bg-white text-gray-900 flex items-center justify-center hover:scale-105 transition-transform shrink-0"
                    aria-label={`Open ${project.title}`}
                  >
                    ↗
                  </a>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default ProjectsPage;
